import{_ as a,o,c as r,ag as t}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"Sistema de Protecciones (Jerarquía)","description":"","frontmatter":{},"headers":[],"relativePath":"maxstaff/adicional/protecciones.md","filePath":"maxstaff/adicional/protecciones.md"}'),i={name:"maxstaff/adicional/protecciones.md"};function s(n,e,c,d,l,u){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="sistema-de-protecciones-jerarquia" tabindex="-1">Sistema de Protecciones (Jerarquía) <a class="header-anchor" href="#sistema-de-protecciones-jerarquia" aria-label="Permalink to &quot;Sistema de Protecciones (Jerarquía)&quot;">​</a></h1><blockquote><p>MaxStaff cuenta con un sistema de seguridad interno para evitar que miembros del staff de menor rango (ej. Ayudantes o Moderadores) sancionen por accidente o por malicia a los Administradores o Dueños del servidor.</p></blockquote><h2 id="_1-proteger-a-un-staff" tabindex="-1">1. Proteger a un Staff <a class="header-anchor" href="#_1-proteger-a-un-staff" aria-label="Permalink to &quot;1. Proteger a un Staff&quot;">​</a></h2><p>Para hacer que un usuario sea &quot;inmune&quot; a las sanciones dentro del menú de MaxStaff o mediante comandos, debes otorgarle el siguiente permiso desde tu plugin de rangos (ej. <a href="https://luckperms.net/" target="_blank" rel="noreferrer">LuckPerms</a>):</p><ul><li><strong>Permiso:</strong> <code>maxstaff.punish.protected</code></li><li><strong>Efecto:</strong> Si alguien intenta banear, mutear o kickear a este jugador, el plugin bloqueará la acción automáticamente.</li></ul><h2 id="_2-evadir-la-proteccion-override" tabindex="-1">2. Evadir la Protección (Override) <a class="header-anchor" href="#_2-evadir-la-proteccion-override" aria-label="Permalink to &quot;2. Evadir la Protección (Override)&quot;">​</a></h2><p>Los Dueños o Administradores Supremos necesitan tener la capacidad de sancionar a cualquier persona, incluso si esa persona tiene el permiso de protección mencionado arriba. Para ello, existe el permiso de &quot;Override&quot; (Anulación):</p><ul><li><strong>Permiso:</strong> <code>maxstaff.punish.override</code></li><li><strong>Efecto:</strong> Permite ignorar las protecciones. Un jugador con este permiso puede sancionar a quien sea, sin importar si el objetivo está protegido o no.</li></ul><blockquote><p><strong>Recomendación de uso:</strong> Dale <code>maxstaff.punish.protected</code> a todos tus Administradores y Moderadores. Dale <code>maxstaff.punish.override</code> <strong>solo</strong> a los Dueños (Owners) o al rango más alto de tu servidor.</p></blockquote>',9)])])}const f=a(i,[["render",s]]);export{m as __pageData,f as default};
